public class PayrollApprovalWorkflow {
    private final IdempotentRunGuard runGuard;
    private final Set<String> approverRoles = Set.of("PAYROLL_MANAGER", "FINANCE_CONTROLLER");

    public PayrollApprovalWorkflow(IdempotentRunGuard runGuard) {
        this.runGuard = runGuard;
    }

    public ApprovalResult approveRun(String runId, String actorId, String actorRole, String approvalToken) {
        if (!runGuard.tryAcquire("approve:" + runId)) {
            return ApprovalResult.duplicate("Run already being approved");
        }
