                return ApprovalResult.rejected("Actor role not permitted");
            }
            if (!ApprovalTokenVerifier.verify(approvalToken, runId, actorId)) {
                return ApprovalResult.rejected("Invalid approval token");
            }
            return ApprovalResult.approved("Approved by " + actorId);
        } finally {
            runGuard.release("approve:" + runId);
        }
    }
